const runResults = $('Run all enabled discovery sources').all();
const candidates = $input.all();

let totalCreated = 0;
let totalErrors = 0;
const sourceLines = [];

for (const item of runResults) {
  const r = item.json;
  // run-enabled returns an array
  if (Array.isArray(r)) {
    for (const src of r) {
      totalCreated += src.candidates_created || 0;
      if (src.errors && src.errors.length > 0) totalErrors++;
      sourceLines.push(`• ${src.source_name}: +${src.candidates_created} candidatos`);
    }
  }
}

const pendingList = candidates.map(c => c.json);
const pendingCount = pendingList.length;

let msg = `🔍 *Internship Pipeline — Digest diario*\n`;
msg += `📅 ${new Date().toLocaleDateString('es-CO', {weekday:'long', day:'numeric', month:'long'})}\n\n`;

if (totalCreated === 0 && totalErrors === 0 && pendingCount === 0) {
  msg += `✅ Sin novedades hoy. No hay candidatos nuevos ni pendientes.`;
} else {
  if (totalCreated > 0 || sourceLines.length > 0) {
    msg += `📊 *Fuentes corridas hoy:*\n${sourceLines.join('\n') || '— ninguna activa'}\n\n`;
  }
  if (pendingCount > 0) {
    msg += `⏳ *${pendingCount} candidatos pendientes de revisión:*\n`;
    for (const c of pendingList.slice(0, 15)) {
      const emoji = c.confidence_score >= 0.7 ? '🟢' : c.confidence_score >= 0.5 ? '🟡' : '🔴';
      const title = c.detected_job_title || 'Posición sin título';
      const company = c.company_name || 'Empresa desconocida';
      const url = c.detected_job_url ? ` — [ver](${c.detected_job_url})` : '';
      msg += `${emoji} *${company}*: ${title}${url}\n`;
    }
    if (pendingCount > 15) {
      msg += `_...y ${pendingCount - 15} más. Abre el dashboard para ver todos._\n`;
    }
    msg += `\n👉 Revisar en: http://localhost:3000/discovery`;
  } else {
    msg += `✅ Sin candidatos pendientes de revisión.`;
  }
  if (totalErrors > 0) {
    msg += `\n\n⚠️ ${totalErrors} fuente(s) con error — revisa los logs.`;
  }
}

return [{ json: { message: msg, pending_count: pendingCount, new_today: totalCreated } }];
